from flask import Flask, request, jsonify
from functools import wraps
import secrets
import hashlib
from datetime import datetime, timedelta

app = Flask(__name__)

# In-memory storage (use a database in production)
users = {
    'user1': hashlib.sha256('password1'.encode()).hexdigest(),
    'user2': hashlib.sha256('password2'.encode()).hexdigest()
}

tokens = {}

def generate_token():
    return secrets.token_hex(32)

def token_required(f):
    @wraps(f)
    def decorated(*args, **kwargs):
        token = request.headers.get('Authorization')
        
        if not token:
            return jsonify({'message': 'Token is missing'}), 401
        
        if token.startswith('Bearer '):
            token = token[7:]
        
        if token not in tokens:
            return jsonify({'message': 'Invalid token'}), 401
        
        token_data = tokens[token]
        if datetime.now() > token_data['expiry']:
            del tokens[token]
            return jsonify({'message': 'Token has expired'}), 401
        
        return f(token_data['username'], *args, **kwargs)
    
    return decorated

@app.route('/login', methods=['POST'])
def login():
    data = request.get_json()
    
    if not data or 'username' not in data or 'password' not in data:
        return jsonify({'message': 'Missing credentials'}), 400
    
    username = data['username']
    password = data['password']
    
    hashed_password = hashlib.sha256(password.encode()).hexdigest()
    
    if username not in users or users[username] != hashed_password:
        return jsonify({'message': 'Invalid credentials'}), 401
    
    token = generate_token()
    tokens[token] = {
        'username': username,
        'expiry': datetime.now() + timedelta(hours=1)
    }
    
    return jsonify({
        'message': 'Login successful',
        'token': token,
        'expires_in': 3600
    }), 200

@app.route('/protected', methods=['GET'])
@token_required
def protected(username):
    return jsonify({
        'message': f'Hello {username}, you have access to this protected resource',
        'data': 'This is sensitive information'
    }), 200

@app.route('/logout', methods=['POST'])
@token_required
def logout(username):
    token = request.headers.get('Authorization')
    if token.startswith('Bearer '):
        token = token[7:]
    
    if token in tokens:
        del tokens[token]
    
    return jsonify({'message': 'Logout successful'}), 200

@app.route('/register', methods=['POST'])
def register():
    data = request.get_json()
    
    if not data or 'username' not in data or 'password' not in data:
        return jsonify({'message': 'Missing credentials'}), 400
    
    username = data['username']
    password = data['password']
    
    if username in users:
        return jsonify({'message': 'User already exists'}), 409
    
    users[username] = hashlib.sha256(password.encode()).hexdigest()
    
    return jsonify({'message': 'User registered successfully'}), 201

if __name__ == '__main__':
    app.run(debug=True, port=5000)